import csv
import sys
import datetime
import re

def normalize_date(date_str):
    formats = ['%m/%d/%Y', '%Y-%m-%d', '%d-%b-%Y']
    date_str = date_str.strip()
    for fmt in formats:
        try:
            return datetime.datetime.strptime(date_str, fmt).strftime('%Y-%m-%d')
        except ValueError:
            continue
    return date_str  # if can't parse, leave as is

def normalize_phone(phone_str):
    phone_str = phone_str.strip()
    digits = re.sub(r'\D', '', phone_str)
    if len(digits) == 10:
        return f'+1{digits}'
    elif len(digits) == 11 and digits[0] == '1':
        return f'+{digits}'
    else:
        return phone_str

def normalize_currency(curr_str):
    curr_str = curr_str.strip()
    cleaned = re.sub(r'[$,]', '', curr_str)
    try:
        return str(float(cleaned))
    except ValueError:
        return curr_str

def main(input_path, output_path):
    with open(input_path, 'r', newline='') as infile:
        reader = csv.reader(infile)
        original_rows = [row for row in reader]

    cleaned_rows = []
    changed_count = 0

    header = original_rows[0]
    cleaned_rows.append(header)

    for row in original_rows[1:]:
        # strip all cells
        stripped_row = [cell.strip() for cell in row]
        name = stripped_row[0]
        phone = normalize_phone(stripped_row[1])
        amount = normalize_currency(stripped_row[2])
        date = normalize_date(stripped_row[3])
        email = stripped_row[4]

        cleaned_row = [name, phone, amount, date, email]
        cleaned_rows.append(cleaned_row)

        # count changes: compare original row with cleaned_row
        for orig, clean in zip(row, cleaned_row):
            if orig != clean:
                changed_count += 1

    with open(output_path, 'w', newline='') as outfile:
        writer = csv.writer(outfile)
        writer.writerows(cleaned_rows)

    print(changed_count)

if __name__ == '__main__':
    if len(sys.argv) != 3:
        print("Usage: python csv_normalizer.py <input_path> <output_path>")
        sys.exit(1)
    main(sys.argv[1], sys.argv[2])

